const runAll = db.transaction((rows) => {
  let count = 0;
  for (const row of rows) {
    const r = insert.run(...row);
    if (r.changes > 0) count++;
  }
  return count;
});

const inserted = runAll(sections);
const total = db.prepare('SELECT COUNT(*) as c FROM law_sections').get();
console.log(`✅ Inserted ${inserted} new sections. Total in DB: ${total.c}`);
db.close();